module data_forwarding_unit (
    input [4:0] data1,
    input [4:0] data2,
    input [1:0] forward_signal,
    output reg [4:0] forwarded_data
);
    always @(*) begin
        case (forward_signal)
            2'b00: forwarded_data = data1;
            2'b01: forwarded_data = data2;
            2'b10: forwarded_data = data1 + data2;
            2'b11: forwarded_data = 5'b00000;
            default: forwarded_data = 5'b00000;
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      if (forward_signal == 2'b00) begin
        forwarded_data <= data2;
      end else if (forward_signal == 2'b01) begin
        forwarded_data <= data1;
      end else if (forward_signal == 2'b10) begin
        forwarded_data <= data2 + data1;
      end else if (forward_signal == 2'b11) begin
        forwarded_data <= 5'b11111;
      end
    end
  end

endmodule

